(()=>{(()=>{let e=document.documentElement;e.classList.remove("no-js"),e.classList.add("js");try{let t=localStorage.getItem("theme"),o=t==="light"||t==="dark"?t:window.matchMedia("(prefers-color-scheme: dark)").matches?"dark":"light";e.dataset.theme=o,e.classList.add("preload-theme")}catch(t){}window.addEventListener("DOMContentLoaded",()=>{requestAnimationFrame(()=>document.documentElement.classList.remove("preload-theme"))})})();})();
